INSERT INTO seputar (id, deskripsi_desa, visi_desa, misi_desa, sejarah_desa, deskripsi_kelompok, visi_kelompok, misi_kelompok) VALUES 
('1', 'Desa Kertasari yang terletak di Kecamatan Bojong, Kabupaten Purwakarta, merupakan wilayah yang dikelilingi oleh bentang alam agraris yang subur dan udara yang sejuk. Kehidupan masyarakat Kertasari kental dengan nilai-nilai budaya Sunda, terutama semangat gotong royong (sabilulungan) dalam kehidupan sehari-hari, mulai dari aktivitas pertanian, perkebunan, hingga kegiatan sosial kemasyarakatan.

Desa ini merupakan gabungan dari berbagai elemen masyarakat yang berfokus pada perkembangan ekonomi lokal, pelestarian budaya, dan peningkatan kesejahteraan bersama melalui berbagai inisiatif komunitas.', 'Mewujudkan program pengabdian masyarakat yang berkelanjutan, inovatif, dan berdaya guna dalam rangka meningkatkan kualitas hidup dan kemandirian masyarakat Desa Kertasari.', '["Menginisiasi dan mengawal program-program pemberdayaan ekonomi masyarakat dan UMKM lokal.","Memfasilitasi kegiatan edukasi, kesehatan, dan keterampilan bagi masyarakat Kertasari.","Membangun sinergi kolaboratif antara mahasiswa, pemerintah desa, tokoh masyarakat, dan warga."]', 'Seiring dengan perkembangan zaman, Kertasari terus beradaptasi. Masyarakat bersama dengan pemuda dan elemen pemerintahan desa bahu-membahu memajukan berbagai sektor strategis seperti pendidikan, ekonomi kreatif, dan infrastruktur desa, tanpa meninggalkan kearifan lokal yang telah diwariskan oleh para leluhur.

Sejarah Desa Kertasari tidak lepas dari perjuangan para tokoh masyarakat terdahulu yang membangun pondasi sosial, budaya, dan infrastruktur dasar. Gotong royong yang telah menjadi tradisi turun-temurun inilah yang menjaga kekompakan warga dalam menghadapi masa demi masa.', 'Kelompok KPPM STIE Wikara Desa Kertasari merupakan wujud pengabdian nyata civitas akademika Sekolah Tinggi Ilmu Ekonomi Wikara Purwakarta yang berlandaskan pada tri dharma perguruan tinggi. Kami hadir membawa bekal keilmuan akademis manajemen ekonomi dan akuntansi yang diintegrasikan secara dinamis ke dalam tata kelola program kerja pedesaan berkualitas tinggi. Fokus pengabdian kami mencakup aspek kesehatan lingkungan fisik (gerakan gotong royong Ngosrek dan penyediaan bak sampah taktis), peningkatan keselamatan pengguna jalan (pemasangan 668 unit mata kucing dan tiang paralon keselamatan reflektif), pendampingan pendidikan kreatif ramah anak serta pelestarian budaya (program Teras Belajar Desa dan Pelatihan Seni Tari Tradisional), hingga festival kesegaran kemasyarakatan ''Sehat Bareng Wikara'' yang mengusung jalan santai dan kaulinan barudak. Seluruh rangkaian program ini dikawal dengan tingkat kepatuhan akuntansi kas yang transparan, manajemen administratif yang solid, dan output publikasi naskah jurnal ilmiah bermutu.', 'Menjadi pelopor pembangunan dan pemberdayaan masyarakat pedesaan yang unggul, cerdas, aman secara infrastruktur, dan sadar lingkungan berlandaskan nilai-nilai kepemimpinan manajemen, akuntabilitas keuangan, dan kepedulian sosial berstandar STIE Wikara di Desa Kertasari.', '["Mengakselerasi peningkatan keselamatan infrastruktur jalan desa melalui kalkulasi presisi dan pemasangan 668 unit mata kucing pemantul cahaya serta instalasi penanda jalan reflektif.","Meningkatkan higiene sosial dan kepedulian lingkungan warga melalui aksi sabilulungan ''Ngosrek'' massal serta penyaluran tempat sampah terklasifikasi di titik-titik krusial desa.","Mencerdaskan anak bangsa melalui Teras Belajar Desa yang interaktif, menumbuhkan kepedulian bakat tari nusantara, dan mempromosikan kebugaran fisik serta kerja sama lewat ''Sehat Bareng Wikara''.","Menerapkan tata kelola kas keuangan pengabdian yang akurat dan tervalidasi nota, pelaksanaan tertib persuratan/administrasi, serta penyusunan buku laporan akhir dan publikasi draf jurnal ilmiah yang kredibel."]');
